def write_report(out,decision,m):
    lines=[f"# {TASK}","","D97 trains/evaluates fair surrogate routers using non-truth inference-time feature signals only.","",f"- decision: `{decision['decision']}`",f"- next: `{decision['next']}`",f"- best fair surrogate: `{m['surrogate_best_fair_arm']}`",f"- best fair accuracy: `{m['surrogate_best_fair_accuracy']}`",f"- low-cost/OOD/top1 tail score: `{m['surrogate_best_fair_low_cost_ood_top1_ambiguity_tail_score']}`","","## Boundary","",BOUNDARY,""]
    (out/"report.md").write_text("\n".join(lines),encoding="utf-8")

def main():
    p=argparse.ArgumentParser(); p.add_argument("--out",default=str(DEFAULT_OUT)); p.add_argument("--seeds",default="18001,18002,18003,18004,18005,18006,18007,18008"); p.add_argument("--train-rows-per-seed",type=int,default=420); p.add_argument("--test-rows-per-seed",type=int,default=420); p.add_argument("--ood-rows-per-seed",type=int,default=420); p.add_argument("--stress-seeds",default="18101,18102,18103,18104"); p.add_argument("--stress-rows-per-seed",type=int,default=540); p.add_argument("--workers",default="auto"); p.add_argument("--cpu-target",default="50-75"); p.add_argument("--heartbeat-sec",type=int,default=20); args=p.parse_args(); os.environ.setdefault("OMP_NUM_THREADS","1"); os.environ.setdefault("MKL_NUM_THREADS","1"); os.environ.setdefault("OPENBLAS_NUM_THREADS","1")
    out=Path(args.out); out.mkdir(parents=True,exist_ok=True); write_json(out/"queue.json",{"task":TASK,"created_at":round(time.time(),3),"seeds":parse_seeds(args.seeds),"rows_per_seed":{"train":args.train_rows_per_seed,"test":args.test_rows_per_seed,"ood":args.ood_rows_per_seed},"stress_seeds":parse_seeds(args.stress_seeds),"stress_rows_per_seed":args.stress_rows_per_seed,"stress_modes":STRESS_MODES,"workers":args.workers,"cpu_target":args.cpu_target,"heartbeat_sec":args.heartbeat_sec}); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"phase0","message":"starting D97 D96 upstream audit"})
    restore=ensure_d96(args); write_json(out/"artifact_restore_report.json",restore); manifest=d96_manifest(restore); write_json(out/"d96_upstream_manifest.json",manifest); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"run","message":"building D97 surrogate training prototype reports"}); agg,dec=build_reports(args,out,manifest); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"complete","decision":dec["decision"]})
    m=agg["metrics"]; print(json.dumps({"task":TASK,"out":str(out),"decision":dec["decision"],"next":dec["next"],"surrogate_best_fair_arm":m["surrogate_best_fair_arm"],"surrogate_best_fair_accuracy":m["surrogate_best_fair_accuracy"],"failed_jobs":m["failed_jobs"]},indent=2))
